// Context tree — the structure of the model context after compaction.
// Leaf tokens sum to their parent; parents sum to RUN.tokensAfter.
interface ContextNode {
  id: string;
  label: string;
  description?: string;
  tokens: number;
  isExpanded?: boolean;
  children?: ContextNode[];
}

