// KPI shape shared by every tab. \`sentiment\` inverts the delta color for
// metrics where a drop is good (bounce rate, refunds) or a rise is bad
// (checkout errors).
interface Kpi {
  label: string;
  value: string;
  delta: {
    value: string;
    direction: 'up' | 'down' | 'flat';
    sentiment?: 'positive' | 'negative' | 'neutral';
  };
  description: string;
}

