type TicketStatus = 'open' | 'pending' | 'resolved';
type TicketPriority = 'urgent' | 'high' | 'normal';

interface TicketRow extends Record<string, unknown> {
  id: string;
  subject: string;
  category: string;
  requester: string;
  company: string;
  status: TicketStatus;
  priority: TicketPriority;
  assignee: string | null;
  updated: string;
  isArchived: boolean;
}

